Array.prototype.myFilter = function(callbackFn, thisArg) {
  if (this == null) throw new TypeError('Array.prototype.myFilter called on null/undefined');
  if (typeof callbackFn !== 'function') throw new TypeError(String(callbackFn) + ' is not a function');

  const arr = Object(this);
  const len = arr.length >>> 0; // snapshot length once
  const result = [];

  for (let i = 0; i < len; i++) {
    // skip holes (and skip indices that were never present)
    if (Object.prototype.hasOwnProperty.call(arr, i)) {
      const val = arr[i];
      if (callbackFn.call(thisArg, val, i, arr)) {
        result.push(val);
      }
    }
  }

  return result;
};
